#include <bits/stdc++.h>
using namespace std;

const int mod=1e9+7;

struct Node{
    int a[11][11];
    Node operator*(Node &x)const{
        Node res;
        for(int i=0;i<11;i++)
            for(int j=0;j<11;j++){
                res.a[i][j]=0;
                for(int k=0;k<11;k++)
                    res.a[i][j]=(res.a[i][j]+1ll*a[i][k]*x.a[k][j])%mod;
            }
        return res; 
    }
}ans,base;

int main(){
    long long n;
    int k;
    scanf("%lld%d",&n,&k);
    memset(base.a,0,sizeof(base.a));
    base.a[0][0]=1;
    for(int i=0;i<=k;i++)
        for(int j=i;j<=k;j++)
            if(i || j)
                base.a[i][j]=base.a[i-1][j-1]+base.a[i][j-1];
    base.a[k][k]=2;
    for(int i=0;i<=k;i++)
        for(int j=0;j<=k;j++)
            ans.a[i][j]=(i==j);
    while(n){
        if(n&1)
            ans=ans*base;
        base=base*base,n>>=1;
    }
    printf("%d",ans.a[0][k]);
    return 0;
}
